rule "Nutanix - Parse API Audit"
when
    has_field("message") AND
    contains(to_string($message.message), "api_audit:")
then
    let msg = to_string($message.message);
    set_field("nutanix_client_type", regex_replace(".*clientType=([^|]+)\\|\\|.*", msg, "$1"));
    set_field("nutanix_user", regex_replace(".*userName=([^|]+)\\|\\|.*", msg, "$1"));
    set_field("nutanix_http_method", regex_replace(".*httpMethod=([^|]+)\\|\\|.*", msg, "$1"));
    set_field("nutanix_api_version", regex_replace(".*NutanixApiVersion=([^|]+)\\|\\|.*", msg, "$1"));
    set_field("nutanix_endpoint", regex_replace(".*restEndpoint=([^|]*)\\|\\|.*", msg, "$1"));
    set_field("nutanix_entity_uuid", regex_replace(".*entityUuid=([^|]*)\\|\\|.*", msg, "$1"));
    set_field("nutanix_log_type", "api_audit");
end

rule "Nutanix - Parse Flow Service Logs"
when
    has_field("message") AND
    contains(to_string($message.message), "flow_service_logs")
then
    let msg = to_string($message.message);
    set_field("nutanix_log_type", "flow_service");
    set_field("nutanix_flow_level", regex_replace(".*Z\\s+([A-Z]+)\\s+.*", msg, "$1"));
    set_field("nutanix_flow_message", regex_replace(".*\\d{4}\\s+(.*)", msg, "$1"));
end

rule "Nutanix - Flag API Error Response"
when
    has_field("message") AND
    contains(to_string($message.message), "responseCode=") AND
    NOT contains(to_string($message.message), "responseCode=200")
then
    let msg = to_string($message.message);
    set_field("nutanix_response_code", regex_replace(".*responseCode=([0-9]+).*", msg, "$1"));
    set_field("nutanix_api_error", true);
    set_field("nutanix_alert_type", "api_error");
end

rule "Nutanix - Flag Critical Operations"
when
    (
        has_field("nutanix_http_method") AND (
            contains(to_string($message.nutanix_http_method), "DELETE") OR
            contains(to_string($message.nutanix_http_method), "PUT") OR
            contains(to_string($message.nutanix_http_method), "POST")
        )
    ) OR (
        has_field("nutanix_operation") AND (
            contains(to_string($message.nutanix_operation), "Delete") OR
            contains(to_string($message.nutanix_operation), "Update") OR
            contains(to_string($message.nutanix_operation), "Create")
        )
    )
then
    set_field("nutanix_critical_operation", true);
    set_field("nutanix_alert_type", "critical_operation");
end

rule "Nutanix - Parse Audit JSON"
when
    has_field("message") AND
    contains(to_string($message.message), "consolidated_audit:")
then
    let msg = to_string($message.message);
    let json_part = regex_replace(".*consolidated_audit:\\s*(\\{.*\\})", msg, "$1");
    let parsed = parse_json(to_string(json_part));
    let json_fields = select_jsonpath(parsed, {
        userName: "$.userName",
        operationType: "$.operationType",
        recordType: "$.recordType",
        severity: "$.severity",
        defaultMsg: "$.defaultMsg",
        affectedEntity: "$.affectedEntityList[0].name",
        entityType: "$.affectedEntityList[0].entityType"
    });
    set_field("nutanix_user", to_string(json_fields.userName));
    set_field("nutanix_operation", to_string(json_fields.operationType));
    set_field("nutanix_record_type", to_string(json_fields.recordType));
    set_field("nutanix_severity", to_string(json_fields.severity));
    set_field("nutanix_message", to_string(json_fields.defaultMsg));
    set_field("nutanix_entity", to_string(json_fields.affectedEntity));
    set_field("nutanix_entity_type", to_string(json_fields.entityType));
    set_field("nutanix_log_type", "audit");
end

rule "Nutanix CVM - Extract Fields"
when
    has_field("message") AND contains(to_string($message.message), "audispd")
then
    let msg = to_string($message.message);
    set_field("ntnx_node", regex_replace(".*node=([^ ]+).*", msg, "$1"));
    set_field("ntnx_type", regex_replace(".*type=([^ ]+).*", msg, "$1"));
    set_field("ntnx_acct", regex_replace(".*acct=\"([^\"]+)\".*", msg, "$1"));
    set_field("ntnx_exe", regex_replace(".*exe=\"([^\"]+)\".*", msg, "$1"));
    set_field("ntnx_result", regex_replace(".*res=([^ ']+).*", msg, "$1"));
    set_field("nutanix_log_type", "cvm_audit");
end

pipeline "Nutanix - Prism Central Parser"
stage 0 match either
    rule "Nutanix - Parse API Audit";
    rule "Nutanix - Parse Flow Service Logs";
    rule "Nutanix - Parse Audit JSON";
    rule "Nutanix - Flag API Error Response";
stage 1 match either
    rule "Nutanix - Flag External Access";
    rule "Nutanix - Flag Critical Operations";
end

pipeline "Nutanix - OS Audit Parser"
stage 0 match either
    rule "Nutanix CVM - Drop Broken";
stage 1 match either
    rule "Nutanix CVM - Extract Fields";
end
